int MangledHashG(const char *key, const int *T)
{
    int sum = 0;

    for (int i = 0; key[i] != '\0'; i++)
    {
        sum += T[i] * key[i];
        sum %= 2678;
    }
    return mangledkG[sum];
}

int MangledPerfectHash(const char *key)
{
    if (strlen(key) > 40)
    {
        return 0;
    }

    return (MangledHashG(key, mangledkT1) + MangledHashG(key, mangledkT2)) % 2678;
}

